  1	import * as React from 'react';
  2	import { TabProps, Tabs } from '@patternfly/react-core';
  3	import { location, router } from '../../app/History';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { PFColors } from 'components/Pf/PfColors';
  6	import { classes } from 'typestyle';
  7	
  8	type TabsProps = {
  9	  activeTab: string;
 10	  className?: string;
 11	  defaultTab: string;
 12	  id: string;
 13	  mountOnEnter?: boolean;
 14	  onSelect: (tabName: string) => void;
 15	  postHandler?: (tabName: string) => void;
 16	  tabMap: { [key: string]: number };
 17	  tabName?: string;
 18	  unmountOnExit?: boolean;
 19	};
 20	
 21	export const activeTab = (tabName: string, defaultTab: string): string => {
 22	  return new URLSearchParams(location.getSearch()).get(tabName) || defaultTab;
 23	};
 24	
 25	const tabStyle = kialiStyle({
 26	  backgroundColor: PFColors.BackgroundColor100
 27	});
 28	
 29	type TabElement = React.ReactElement<TabProps, React.JSXElementConstructor<TabProps>>;
 30	
 31	type TabMap = { [key: number]: string };
 32	
 33	export class ParameterizedTabs extends React.Component<TabsProps> {
 34	  private indexMap: TabMap;
 35	  private tabLinks: TabMap;
 36	
 37	  constructor(props: TabsProps) {
 38	    super(props);
 39	    this.indexMap = this.buildIndexMap();
 40	    this.tabLinks = this.buildTabLinks();
 41	  }
 42	
 43	  componentDidUpdate(): void {
 44	    this.indexMap = this.buildIndexMap();
 45	    this.tabLinks = this.buildTabLinks();
 46	  }
 47	
 48	  buildIndexMap(): TabMap {
 49	    return Object.keys(this.props.tabMap).reduce((result: { [i: number]: string }, name: string) => {
 50	      result[this.tabIndexOf(name)] = name;
 51	      return result;
 52	    }, {});
 53	  }
 54	
 55	  buildTabLinks(): TabMap {
 56	    const tabLinks: TabMap = {};
 57	
 58	    React.Children.forEach(this.props.children, child => {
 59	      const childComp = child as React.ReactElement<TabProps>;
 60	
 61	      if (childComp.props.href) {
 62	        tabLinks[childComp.props.eventKey] = childComp.props.href;
 63	      }
 64	    });
 65	
 66	    return tabLinks;
 67	  }
 68	
 69	  tabIndexOf(tabName: string): number {
 70	    return this.props.tabMap[tabName];
 71	  }
 72	
 73	  tabNameOf(index: number): string {
 74	    return this.indexMap[index];
 75	  }
 76	
 77	  activeIndex = (): number => {
 78	    return this.tabIndexOf(this.props.activeTab);
 79	  };
 80	
 81	  isLinkTab = (index: number): boolean => {
 82	    return this.tabLinks[index] != null;
 83	  };
 84	
 85	  tabSelectHandler = (tabKey: string): void => {
 86	    const urlParams = new URLSearchParams(location.getSearch());
 87	
 88	    if (!!this.props.tabName) {
 89	      urlParams.set(this.props.tabName, tabKey);
 90	      router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
 91	    }
 92	
 93	    if (this.props.postHandler) {
 94	      this.props.postHandler(tabKey);
 95	    }
 96	
 97	    this.setState({
 98	      currentTab: tabKey
 99	    });
100	  };
101	
102	  tabTransitionHandler = (tabKey: number): void => {
103	    const tabName = this.tabNameOf(tabKey);
104	    this.tabSelectHandler(tabName);
105	    this.props.onSelect(tabName);
106	  };
107	
108	  render(): React.ReactNode {
109	    return (
110	      <Tabs
111	        id={this.props.id}
112	        className={classes(this.props.className, tabStyle)}
113	        activeKey={this.activeIndex()}
114	        onSelect={(_, ek) => {
115	          if (!this.isLinkTab(ek as number)) {
116	            this.tabTransitionHandler(ek as number);
117	          }
118	        }}
119	        mountOnEnter={this.props.mountOnEnter === undefined ? true : this.props.mountOnEnter}
120	        unmountOnExit={this.props.unmountOnExit === undefined ? true : this.props.unmountOnExit}
121	      >
122	        {!Array.isArray(this.props.children)
123	          ? (this.props.children as TabElement)
124	          : this.props.children.map(child => child)}
125	      </Tabs>
126	    );
127	  }
128	}

